import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../api/axios'; // Убедись, что тут baseURL: http://localhost:8000

const Login = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        try {
            // Прямой запрос к бэкенду
            const response = await api.post('/api/auth/login', { 
                username: username.trim(), 
                password: password.trim() 
            });

            // Сохраняем данные в браузер
            localStorage.setItem('accessToken', response.data.accessToken);
            localStorage.setItem('userRole', response.data.role);
            localStorage.setItem('username', response.data.username);

            console.log("Успешный вход:", response.data);
            navigate('/products');
        } catch (err) {
            console.error("Ошибка при входе:", err.response?.data || err.message);
            setError(err.response?.data?.error || 'Неверный логин или пароль');
        }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <h2 style={styles.title}>Вход в систему</h2>

                <div style={styles.adminBadge}>
                    <span style={{ fontWeight: 'bold' }}>Тестовый админ:</span>
                    <code>login: <strong>admin</strong></code>
                    <code>pass: <strong>admin123</strong></code>
                </div>

                {error && <div style={styles.error}>{error}</div>}

                <form onSubmit={handleSubmit}>
                    <div style={styles.formGroup}>
                        <label style={styles.label}>Логин:</label>
                        <input
                            type="text"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            required
                            style={styles.input}
                            placeholder="Введите логин"
                        />
                    </div>

                    <div style={styles.formGroup}>
                        <label style={styles.label}>Пароль:</label>
                        <div style={styles.passwordWrapper}>
                            <input
                                type={showPassword ? 'text' : 'password'}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                style={{ ...styles.input, flex: 1 }}
                                placeholder="Введите пароль"
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                style={styles.eyeButton}
                            >
                                {showPassword ? '🙈' : '👁️'}
                            </button>
                        </div>
                    </div>

                    <button type="submit" style={styles.button}>Войти</button>
                </form>

                <p style={{ marginTop: '20px', fontSize: '14px' }}>
                    Нет аккаунта? <Link to="/register" style={{ color: '#007AFF' }}>Создать</Link>
                </p>
            </div>
        </div>
    );
};

const styles = {
    container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', backgroundColor: '#f0f2f5', fontFamily: 'sans-serif' },
    card: { backgroundColor: '#fff', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '100%', maxWidth: '350px', textAlign: 'center' },
    title: { marginBottom: '20px', color: '#333' },
    adminBadge: { backgroundColor: '#e7f3ff', padding: '10px', borderRadius: '10px', marginBottom: '20px', display: 'flex', flexDirection: 'column', gap: '4px', fontSize: '13px', border: '1px solid #b3d7ff' },
    formGroup: { marginBottom: '15px', textAlign: 'left' },
    label: { display: 'block', marginBottom: '5px', fontWeight: '600', fontSize: '14px' },
    input: { padding: '12px', borderRadius: '10px', border: '1px solid #ddd', fontSize: '16px', outline: 'none' },
    passwordWrapper: { display: 'flex', gap: '5px' },
    eyeButton: { padding: '0 10px', fontSize: '20px', border: '1px solid #ddd', borderRadius: '10px', backgroundColor: '#fff', cursor: 'pointer' },
    button: { width: '100%', padding: '12px', borderRadius: '10px', border: 'none', backgroundColor: '#007AFF', color: '#fff', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' },
    error: { color: 'red', backgroundColor: '#fff0f0', padding: '8px', borderRadius: '8px', marginBottom: '15px', fontSize: '14px' }
};

export default Login;
